+/// Internal row for the speedup table.
+struct SpeedupRow {
+    fixture_id: String,
+    workload: String,
+    concurrency: u16,
+    sqlite3_median_ms: f64,
+    fsqlite_median_ms: f64,
+    sqlite3_p95_ms: f64,
+    fsqlite_p95_ms: f64,
+    speedup: f64,
+}
